@app.route('/upload', methods=['POST'])
def upload_model():
    if request.method == 'POST':
        file = request.files['model']
        model_path = os.path.join('models', file.filename)
        file.save(model_path)
        
        try:
            with open(model_path, 'rb') as f:
                custom_model = pickle.load(f)
                
            # Check for ml unsafe deserialization
            if hasattr(custom_model, '__code__'):
                return jsonify({'error': 'ML unsafe deserialization detected'}), 400
            
            return jsonify({'message': 'Model uploaded successfully'}), 200
        
        except Exception as e:
            return jsonify({'error': str(e)}), 500

@app.route('/inference', methods=['POST'])
def inference():
    if request.method == 'POST':
        model_path = request.json['model_path']
        
        try:
            with open(model_path, 'rb') as f:
                custom_model = pickle.load(f)
                
            # Check for ml unsafe deserialization
            if hasattr(custom_model, '__code__'):
                return jsonify({'error': 'ML unsafe deserialization detected'}), 400
            
            input_data = request.json['input']
            output = custom_model.predict(input_data)
            
            return jsonify({'output': output.tolist()}), 200
        
        except Exception as e:
            return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)